use std::collections::HashMap;

struct GameAsset {
    name: String,
    id: u32,
}

fn process_and_regroup_assets(list_a: Vec<String>, list_b: Vec<u32>) -> (Vec<(String, u32)>, HashMap<String, Vec<u32>>) {
    let zipped_pairs: Vec<(String, u32)> = list_a.into_iter().zip(list_b.into_iter()).collect();

    let mut regrouped_map: HashMap<String, Vec<u32>> = HashMap::new();

    for (name, id) in zipped_pairs.iter() {
        regrouped_map.entry(name.clone()).or_default().push(*id);
    }

    let final_pairs: Vec<(String, u32)> = zipped_pairs;
    (final_pairs, regrouped_map)
}

use std::collections::HashMap;

struct SensorReading {
    temperature: f32,
    humidity: f32,
    voltage: f32,
}

fn main() {
    let temps = vec![20.5, 21.0, 19.8];
    let hums = vec![60.2, 61.5, 59.0];
    let vols = vec![3.7, 3.65, 3.8];

    let combined_readings: Vec<SensorReading> = temps.into_iter()
        .zip(hums.into_iter())
        .zip(vols.into_iter())
        .map(|((t, h), v)| SensorReading { 
            temperature: t,
            humidity: h,
            voltage: v,
        })
        .collect();

    println!("Combined Readings:");
    for reading in &combined_readings {
        println!("T: {:.1}, H: {:.1}, V: {:.2}", 
                 reading.temperature, reading.humidity, reading.voltage);
    }

    let temps_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.temperature)
        .collect();

    let hums_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.humidity)
        .collect();

    let vols_only: Vec<f32> = combined_readings.iter()
        .map(|r| r.voltage)
        .collect();

    println!("nUnzipped Temperature Readings (First 2): ");
    for i in 0..std::cmp::min(2, temps_only.len()) {
        println!("{:.1}", temps_only[i]);
    }
}

use std::collections::HashMap;

struct JobResult {
    key: String,
    value: i32,
    timestamp: u64,
}

fn process_results(keys: Vec<String>, values: Vec<i32>, timestamps: Vec<u64>) -> HashMap<String, (i32, u64)> {
    let mut combined_map = HashMap::new();
    let min_len = keys.len().min(values.len()).min(timestamps.len());

    for i in 0..min_len {
        let key = &keys[i];
        let value = values[i];
        let timestamp = timestamps[i];
        combined_map.insert(key.clone(), (value, timestamp));
    }
    combined_map
}

fn main() {
    let keys = vec!["A".to_string(), "B".to_string(), "C".to_string()];
    let values = vec![10, 20, 30];
    let timestamps = vec![1678886400, 1678886500, 1678886600];

    let results = process_results(keys, values, timestamps);

    for (key, (value, timestamp)) in results {
        println!("Key: {}, Value: {}, Timestamp: {}", key, value, timestamp);
    }
}

use std::collections::HashMap;

struct SensorReading {
    temperature: f32,
    humidity: f32,
}

fn process_sensor_data(temps: Vec<f32>, humids: Vec<f32>) -> Result<Vec<SensorReading>, String> {
    if temps.len() != humids.len() {
        return Err("Temperature and humidity vectors must have the same length".to_string());
    }

    let mut readings = Vec::new();

    for (i, &temp) in temps.iter().enumerate() {
        let hum = humids[i];
        readings.push(SensorReading { temperature: temp, humidity: hum });
    }

    Ok(readings)
}

fn main() {
    let temperatures = vec![21.5, 22.0, 21.8];
    let humidities = vec![65.0, 64.5, 66.1];

    match process_sensor_data(temperatures, humidities) {
        Ok(readings) => {
            for reading in readings {
                println!("Processed Reading: Temp={}, Humidity={}", reading.temperature, reading.humidity);
            }
        },
        Err(e) => {
            eprintln!("Error processing data: {}", e);
        }
    }

    let short_temps = vec![10.0];
    let long_humids = vec![50.0, 51.0];

    match process_sensor_data(short_temps, long_humids) {
        Ok(_) => {},
        Err(e) => {
            println!("Caught expected error: {}", e);
        }
    }
}

use std::collections::HashMap;

struct ProductPair {
    id: u32,
    price: f64,
}

fn main() {
    let ids = vec![101, 102, 103];
    let prices = vec![9.99, 12.50, 20.00];

    let zipped_products: Vec<ProductPair> = ids.into_iter().zip(prices.into_iter()).map(|(id, price)| {
        ProductPair { id, price }
    }).collect();

    println!("Zipped Products:");
    for product in &zipped_products {
        println!("ID: {}, Price: {}", product.id, product.price);
    }

    let mut id_map: HashMap<u32, f64> = HashMap::new();
    for product in zipped_products {
        id_map.insert(product.id, product.price);
    }

    println!("nUnzipped (as Map):");
    for (id, price) in &id_map {
        println!("ID: {}, Price: {}", id, price);
    }
}
